const crypto = require("crypto");

const input = $input.first().json;

const secret = input.n8n_secrets.job_link_secret;   // pass in securely
const number = String(input.number);
const ttl = Number(input.ttlSeconds ?? 3600);
const sub = input.sub ? String(input.sub) : null;

const now = Math.floor(Date.now() / 1000);
const exp = now + ttl;

// ------------------------------
// Canonical message (MUST match AuthGate)
// ------------------------------
function buildMsg({ job, exp, sub }) {
  let msg = `job=${job}&exp=${exp}`;
  if (sub) msg += `&sub=${sub}`;
  return msg;
}

function formatTTL(seconds) {
  seconds = Math.max(0, Math.floor(Number(seconds) || 0));

  const days = Math.floor(seconds / 86400);
  seconds %= 86400;

  const hours = Math.floor(seconds / 3600);
  seconds %= 3600;

  const minutes = Math.floor(seconds / 60);
  const secs = seconds % 60;

  const parts = [];
  if (days) parts.push(`${days}d`);
  if (hours) parts.push(`${hours}h`);
  if (minutes) parts.push(`${minutes}m`);
  if (secs || parts.length === 0) parts.push(`${secs}s`);

  return parts.join(" ");
}

function expiryIsoFromTTL(ttlSeconds) {
  const ttl = Math.max(0, Number(ttlSeconds) || 0);

  const expiryDate = new Date(Date.now() + ttl * 1000);

  return expiryDate.toISOString(); // ISO 8601 in UTC
}

function formatFriendlyUK(isoString) {
  return new Intl.DateTimeFormat("en-GB", {
    dateStyle: "full",
    timeStyle: "long",
    timeZone: "Europe/London",
  }).format(new Date(isoString));
}

const msg = buildMsg({ job: number, exp, sub });

const auth = crypto
  .createHmac("sha256", secret)
  .update(msg)
  .digest("base64url");

// ------------------------------
// Manual querystring builder
// ------------------------------
function toQueryString(obj = {}) {
  return Object.entries(obj)
    .filter(([, v]) => v !== undefined && v !== null && v !== "")
    .map(([k, v]) =>
      `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`
    )
    .join("&");
}

const query = {
  number,
  exp,
  auth,
};

if (sub) query.sub = sub;

const qs = toQueryString(query);

const url = `${input.baseUrl}?${qs}`;

return [
  {
    json: {
      secureLink: {
        number,
        exp,
        sub,
        auth,
        msg,   // useful for debugging signature mismatches
        url,
        ttl: formatTTL(ttl),
        ttlSeconds: ttl,
        expires: expiryIsoFromTTL(ttl),
        expiresFriendly: formatFriendlyUK(expiryIsoFromTTL(ttl))
      }
    }
  }
];

